from flask import Flask, jsonify
import psycopg2
import redis
import os

app = Flask(__name__)

DATABASE_URL = os.environ.get('DATABASE_URL')
REDIS_URL = os.environ.get('REDIS_URL')

@app.route('/health')
def health():
    """Basic health check - process is running"""
    return jsonify({"status": "healthy"}), 200

@app.route('/health/live')
def liveness():
    """Liveness probe - is the process alive?
    Kubernetes restarts pod if this fails.
    """
    return jsonify({"status": "alive"}), 200

@app.route('/health/ready')
def readiness():
    """Readiness probe - can we serve traffic?
    LB removes from pool if this fails.
    """
    checks = {
        "database": check_database(),
        "cache": check_cache(),
        "dependencies": check_dependencies()
    }

    all_healthy = all(checks.values())
    status_code = 200 if all_healthy else 503

    return jsonify({
        "status": "ready" if all_healthy else "not ready",
        "checks": checks
    }), status_code

def check_database():
    try:
        conn = psycopg2.connect(DATABASE_URL)
        cur = conn.cursor()
        cur.execute('SELECT 1')
        cur.close()
        conn.close()
        return True
    except Exception:
        return False

def check_cache():
    try:
        r = redis.Redis.from_url(REDIS_URL)
        r.ping()
        return True
    except Exception:
        return False

def check_dependencies():
    # Check external APIs, message queues, etc.
    return True

const express = require('express');
const { Pool } = require('pg');
const Redis = require('ioredis');

const app = express();
const pool = new Pool({ connectionString: process.env.DATABASE_URL });
const redis = new Redis(process.env.REDIS_URL);

app.get('/health', (req, res) => {
  res.json({ status: 'healthy' });
});

app.get('/health/live', (req, res) => {
  res.json({ status: 'alive' });
});

app.get('/health/ready', async (req, res) => {
  const checks = {
    database: await checkDatabase(),
    cache: await checkCache(),
  };

  const allHealthy = Object.values(checks).every(v => v);
  const status = allHealthy ? 200 : 503;

  res.status(status).json({
    status: allHealthy ? 'ready' : 'not ready',
    checks
  });
});

async function checkDatabase() {
  try {
    await pool.query('SELECT 1');
    return true;
  } catch {
    return false;
  }
}

async function checkCache() {
  try {
    await redis.ping();
    return true;
  } catch {
    return false;
  }
}

package main

import (
    "context"
    "database/sql"
    "encoding/json"
    "net/http"
    "time"

    "github.com/go-redis/redis/v8"
    _ "github.com/lib/pq"
)

type HealthResponse struct {
    Status string            `json:"status"`
    Checks map[string]bool   `json:"checks,omitempty"`
}

var db *sql.DB
var rdb *redis.Client

func healthHandler(w http.ResponseWriter, r *http.Request) {
    json.NewEncoder(w).Encode(HealthResponse{Status: "healthy"})
}

func livenessHandler(w http.ResponseWriter, r *http.Request) {
    json.NewEncoder(w).Encode(HealthResponse{Status: "alive"})
}

func readinessHandler(w http.ResponseWriter, r *http.Request) {
    ctx, cancel := context.WithTimeout(r.Context(), 5*time.Second)
    defer cancel()

    checks := map[string]bool{
        "database": checkDatabase(ctx),
        "cache":    checkCache(ctx),
    }

    allHealthy := true
    for _, v := range checks {
        if !v {
            allHealthy = false
            break
        }
    }

    status := "ready"
    httpStatus := http.StatusOK
    if !allHealthy {
        status = "not ready"
        httpStatus = http.StatusServiceUnavailable
    }

    w.WriteHeader(httpStatus)
    json.NewEncoder(w).Encode(HealthResponse{
        Status: status,
        Checks: checks,
    })
}

func checkDatabase(ctx context.Context) bool {
    return db.PingContext(ctx) == nil
}

func checkCache(ctx context.Context) bool {
    return rdb.Ping(ctx).Err() == nil
}
